parameters.jsCode:
const inputs = $input.all();

let imageData = null;
let textData = null;

for (const item of inputs) {
  if (item.binary && item.binary.data) {
    imageData = item;
  } else if (item.json && item.json.output) {
    textData = item;
  }
}

if (!imageData || !textData) {
  throw new Error("Faltan datos necesarios: imagen o texto.");
}

// Formatear los hashtags como texto, separados por espacio
const hashtags = (textData.json.output.Hashtags || []).join(" ");

return [
  {
    json: {
      text: textData.json.output["post content"],
      hashtags: hashtags
    },
    binary: {
      data: imageData.binary.data
    }
  }
];
